SELECT rate_plan_name
FROM rate_plans
WHERE is_active = 1;

SELECT customer_id, AVG(usage_gj) AS average_usage
FROM energy_usage
GROUP BY customer_id;

SELECT SUM(amount_due) AS total_remaining_due
FROM billing
WHERE customer_id = 1 AND paid = 0;

SELECT COUNT(customer_id) AS number_of_customers
FROM customers
WHERE contact_info LIKE '%Email:%';

SELECT SUM(usage_gj) AS total_energy_usage
FROM energy_usage
WHERE usage_date BETWEEN '2023-01-01' AND '2023-03-31';

SELECT customer_id, billing_date
FROM billing
LIMIT 2;

SELECT customer_id, SUM(amount_due) AS total_amount_due
FROM billing
GROUP BY customer_id;

SELECT rate_plan_name, effective_start_date
FROM rate_plans
ORDER BY effective_start_date DESC;
